 54â†’		case KindSubstring:
 55â†’			var f SubstringFilter
 56â†’			if err := json.Unmarshal(fi.Value, &f); err != nil {
 57â†’				errs = append(errs, ValidationError{Field: fi.Field,
 58â†’					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 59â†’				continue
 60â†’			}
 61â†’			if len(f.Value) > 512 {
 62â†’				errs = append(errs, ValidationError{Field: fi.Field,
 63â†’					Message: "value exceeds maximum length of 512 characters"})
 64â†’			}
